<template>
  <div 
    class="w-64 h-40 border overflow-y-scroll" 
    @scroll.passive="handleScroll"
    ref="scrollBox"
  >
    <!-- Long content -->
    <p v-for="n in 50" :key="n">Line {{ n }}</p>
  </div>

  <p>Scroll position: {{ scrollTop }}</p>
  <p>Direction: {{ direction }}</p>
</template>

<script>
export default {
  data() {
    return {
      scrollTop: 0,
      lastScrollTop: 0,
      direction: ''
    }
  },
  methods: {
    handleScroll(e) {
      const el = this.$refs.scrollBox
      this.scrollTop = el.scrollTop

      if (this.scrollTop > this.lastScrollTop) {
        this.direction = 'down'
      } else if (this.scrollTop < this.lastScrollTop) {
        this.direction = 'up'
      }

      this.lastScrollTop = this.scrollTop
    }
  }
}
</script>
